#include<bits/stdc++.h>
using namespace std;
#define g(a,b,c,d,e,f) (f-c+10*(b+e-1)*(e-b)/2+e-b+d-a+3*(a+d-1)*(d-a)+5*((d-1)*d*(2*d-1)/6-(a-1)*a*(2*a-1)/6))
long long _,n,a,b,c,d,e,f;
int main(){
    ios::sync_with_stdio(0),cin.tie(0),cout.tie(0),cin>>_;
    for(int i=0;i<_;++i){
        cin>>n>>a>>b>>c>>d>>e>>f;
        cout<<(d>a||(d==a&&(e>b||(e==b&&f>=c)))?g(a,b,c,d,e,f):g(a,b,c,(n-1),(n-1),(10*(n-1)+1))+g(0,0,0,d,e,f))<<"\n";
    }
    return 0;
}
